define(['jquery','core/ajax'],function($,Ajax){return{init:function(cmid,initialState){let lastGameId=initialState&&initialState.gameid?initialState.gameid:0;let lastStatus=initialState&&initialState.status?initialState.status:'';let lastModified=initialState&&initialState.timemodified?initialState.timemodified:0;let lastMoveTime=initialState&&initialState.lastmovetime?initialState.lastmovetime:0;let polling=false;function hasChanged(response){if(!response.hasgame){return false}return response.gameid!==lastGameId||response.status!==lastStatus||response.timemodified>lastModified||response.lastmovetime>lastMoveTime}function poll(){if(polling){return}polling=true;Ajax.call([{methodname:'mod_crossduel_get_game_state',args:{cmid:cmid}}])[0].done(function(response){if(hasChanged(response)){window.location.reload()}}).fail(function(error){console.error('CrossDuel polling error',error)}).always(function(){polling=false})}setInterval(poll,3000)}};});